# Module providing mathematical utility functions and constants

class Calculator:
    @staticmethod
    def add(a: int, b: int) -> int:
        return a + b

    @staticmethod
    def multiply(a: int, b: int) -> int:
        return a * b

    @staticmethod
    def power(base: int, exp: int) -> int:
        result: int = 1
        i: int = 0
        while i < exp:
            result = result * base
            i += 1
        return result

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

PI_APPROXIMATION: float = 3.14159

