# Module for geometric shapes - imports from math_utils
from math_utils import Calculator, PI_APPROXIMATION

class Circle:
    radius: float

    def __init__(self, r: float):
        self.radius = r

    def area(self) -> float:
        # Area = PI * r^2
        r_squared: float = self.radius * self.radius
        return PI_APPROXIMATION * r_squared

    def circumference(self) -> float:
        # Circumference = 2 * PI * r
        return 2.0 * PI_APPROXIMATION * self.radius

class Rectangle:
    width: int
    height: int

    def __init__(self, w: int, h: int):
        self.width = w
        self.height = h

    def area(self) -> int:
        return Calculator.multiply(self.width, self.height)

    def perimeter(self) -> int:
        side_sum: int = Calculator.add(self.width, self.height)
        return Calculator.multiply(side_sum, 2)
